#!/usr/bin/env node
/**
 * Migrates a single template from the Shopify v1 (REST) connector to v2
 * (GraphQL), using the operation map generated by
 * bin/migrations/data/generate-shopify-v2-ops.js.
 *
 * What it does:
 *   - Action steps (trigger_type: output, type: shopify): swaps entity/action/
 *     operation_id to the v2 operation, rebuilds metadata as
 *     {api_endpoint, body, site?, trigger_parent_key?}, sets version "v2",
 *     and regenerates selected_fields. Step name/key/schema/weight/on_error
 *     are preserved verbatim.
 *   - Trigger steps (trigger_type: input, type: shopify): sets version "v2"
 *     and the v2 operation_id (same topic ids as v1). Metadata untouched.
 *   - Rewrites downstream tokens that reference a swapped ACTION step's
 *     output ({{key.field}}, {{key[].field}}, {% for x in key %}) from REST
 *     field names to the v2 GraphQL response shape, validating every path
 *     against the op's response schema. Trigger-payload tokens are never
 *     touched (v2 webhooks keep snake_case).
 *
 * Validation failures (unmapped op, unsupported body field, token referencing
 * a field absent from the v2 response) abort with exit code 2 and no write.
 *
 * Usage:
 *   node bin/migrations/06-shopify-v2.js <template-dir> [--check]
 */
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const OPS_FILE = path.join(path.dirname(fileURLToPath(import.meta.url)), 'data/shopify-v2-ops.json');

/** Metadata keys handled explicitly by the transform (not body fields). */
const PASSTHROUGH_META = ['site', 'trigger_parent_key'];

/**
 * Convert a snake_case identifier to camelCase.
 * @param {string} s Identifier.
 * @returns {string} camelCase form.
 */
function camelize(s) {
    return s.replace(/_([a-z0-9])/g, (m, c) => c.toUpperCase());
}

/**
 * Title-case an identifier (customer -> Customer).
 * @param {string} s Identifier.
 * @returns {string} Title-cased form.
 */
function titlecase(s) {
    return s ? s[0].toUpperCase() + s.slice(1) : s;
}

/**
 * Migration engine for one template directory.
 */
class Migrator {
    /**
     * @param {string} dir Template directory containing mesa.json.
     * @param {object} ops Parsed shopify-v2-ops.json.
     */
    constructor(dir, ops) {
        this.dir = dir;
        this.ops = ops;
        this.swapped = {}; // step key -> ops entry, for token rewriting
        this.report = { swaps: [], tokens: [], warnings: [], errors: [] };
    }

    /**
     * Run the migration.
     * @param {boolean} write Persist mesa.json when validation passes.
     * @returns {boolean} True when no errors.
     */
    run(write) {
        const file = path.join(this.dir, 'mesa.json');
        const raw = fs.readFileSync(file, 'utf8');
        const json = JSON.parse(raw);

        for (const listKey of ['inputs', 'outputs']) {
            const steps = (json.config && json.config[listKey]) || [];
            steps.forEach((step, i) => {
                if (step.type !== 'shopify') {
                    return;
                }
                if (step.version === 'v2') {
                    this.report.warnings.push(`${listKey}[${i}] ${step.key}: already v2, skipped`);
                    return;
                }
                if (step.trigger_type === 'input') {
                    this.migrateTrigger(step, `${listKey}[${i}]`);
                } else {
                    steps[i] = this.migrateAction(step, `${listKey}[${i}]`);
                }
            });
        }

        if (!this.report.errors.length) {
            this.rewriteTokens(json);
        }

        // Final sweep: no v1 shopify step may remain.
        for (const listKey of ['inputs', 'outputs']) {
            for (const step of (json.config && json.config[listKey]) || []) {
                if (step.type === 'shopify' && step.version !== 'v2') {
                    this.report.errors.push(`${step.key}: still v1 after migration`);
                }
            }
        }

        this.print();
        if (this.report.errors.length) {
            return false;
        }
        if (write) {
            const out = JSON.stringify(json, null, 4) + (raw.endsWith('\n') ? '\n' : '');
            fs.writeFileSync(file, out);
            console.log(`\nWROTE ${file}`);
        } else {
            console.log('\nCHECK ONLY: no file written');
        }
        return true;
    }

    /**
     * Migrate a shopify input (trigger) step in place.
     * @param {object} step Step config (mutated).
     * @param {string} where Position label for reporting.
     */
    migrateTrigger(step, where) {
        const v1Key = `${step.entity}/${step.action}`;
        const entry = this.ops.inputs[v1Key];
        if (!entry) {
            this.report.errors.push(`${where} ${step.key}: no v2 trigger for ${v1Key}`);
            return;
        }
        this.insertAfter(step, 'name', 'version', 'v2');
        this.insertAfter(step, 'key', 'operation_id', entry.operation_id);
        this.report.swaps.push(`trigger ${step.key}: ${v1Key} -> v2 ${entry.operation_id}`);
    }

    /**
     * Migrate a shopify output (action) step, returning the rebuilt step.
     * @param {object} step Original step config.
     * @param {string} where Position label for reporting.
     * @returns {object} New step object (original on error).
     */
    migrateAction(step, where) {
        const v1Key = `${step.entity}/${step.action}`;
        const entry = this.ops.outputs[v1Key];
        if (!entry) {
            this.report.errors.push(`${where} ${step.key}: NO V2 EQUIVALENT for ${v1Key} (blocker)`);
            return step;
        }

        const meta = step.metadata || {};
        const consumed = new Set(['api_endpoint']);
        const consumedBody = new Set();
        const body = {};

        // Explicit field rules, then default <entity>_id -> id, then body passthrough.
        const rules = { ...(entry.field_rules || {}) };
        const idKey = `${step.entity}_id`;
        if (!Object.keys(rules).length && entry.request.fields.includes('id') && meta[idKey] !== undefined) {
            rules.id = `@${idKey}`;
        }
        for (const [target, specRaw] of Object.entries(rules)) {
            const [spec, transform] = specRaw.split('|');
            let value;
            if (spec.startsWith('@query:')) {
                const [, metaKey, param] = spec.split(':');
                if (meta[metaKey] === undefined) {
                    continue;
                }
                consumed.add(metaKey);
                value = new URLSearchParams(String(meta[metaKey])).get(param);
                if (value === null) {
                    continue;
                }
            } else if (spec.startsWith('@body.')) {
                const k = spec.slice(6);
                if (!meta.body || meta.body[k] === undefined) {
                    continue;
                }
                consumedBody.add(k);
                value = meta.body[k];
            } else if (spec.startsWith('@')) {
                const k = spec.slice(1);
                if (meta[k] === undefined) {
                    continue;
                }
                consumed.add(k);
                value = meta[k];
            } else if (spec.startsWith('=')) {
                value = spec.slice(1);
            }
            if (transform === 'titlecase' && typeof value === 'string' && !value.includes('{{')) {
                value = titlecase(value);
            }
            body[target] = value;
        }
        for (const [k, v] of Object.entries(meta.body || {})) {
            if (!consumedBody.has(k) && body[k] === undefined) {
                body[k] = v;
            }
        }
        if (meta.body) {
            consumed.add('body');
        }

        // Validate body against the v2 request schema.
        for (const k of Object.keys(body)) {
            if (!entry.request.fields.includes(k)) {
                this.report.errors.push(`${where} ${step.key}: body field "${k}" not in v2 ${entry.v2.operation_id} schema (${v1Key})`);
            }
        }
        for (const k of entry.request.required) {
            if (body[k] === undefined) {
                this.report.errors.push(`${where} ${step.key}: required v2 field "${k}" missing (${v1Key} -> ${entry.v2.operation_id})`);
            } else if (body[k] === '') {
                this.report.warnings.push(`${where} ${step.key}: required field "${k}" is empty (template setup placeholder)`);
            }
        }

        // Unhandled v1 metadata keys are a hard stop: each needs a decision.
        for (const k of Object.keys(meta)) {
            if (!consumed.has(k) && !PASSTHROUGH_META.includes(k)) {
                this.report.errors.push(`${where} ${step.key}: unhandled v1 metadata key "${k}" (${v1Key})`);
            }
        }
        if (this.report.errors.length) {
            return step;
        }

        // Rebuild metadata and selected_fields.
        const newMeta = { api_endpoint: entry.v2.api_endpoint, body };
        for (const k of PASSTHROUGH_META) {
            if (meta[k] !== undefined) {
                newMeta[k] = meta[k];
            }
        }
        const selected = [
            ...Object.keys(body),
            ...(meta.site !== undefined ? ['site'] : []),
            ...(Object.keys(body).length ? ['body', ...Object.keys(body).map((k) => `body.${k}`)] : []),
        ];

        // Rebuild the step preserving original property order.
        const out = {};
        for (const [k, v] of Object.entries(step)) {
            switch (k) {
                case 'entity': out.entity = entry.v2.entity; break;
                case 'action': out.action = entry.v2.action; break;
                case 'metadata': out.metadata = newMeta; break;
                case 'selected_fields': out.selected_fields = selected; break;
                case 'operation_id': out.operation_id = entry.v2.operation_id; break;
                case 'version': break; // re-inserted below
                default: out[k] = v;
            }
            if (k === 'name') {
                out.version = 'v2';
            }
        }
        this.insertAfter(out, 'key', 'operation_id', entry.v2.operation_id);
        if (out.selected_fields === undefined) {
            this.insertAfter(out, 'local_fields', 'selected_fields', selected);
        }

        this.swapped[step.key] = entry;
        this.report.swaps.push(`action ${step.key}: ${v1Key} -> v2 ${entry.v2.operation_id} (body: ${Object.keys(body).join(', ') || 'none'})`);
        return out;
    }

    /**
     * Insert a property after an anchor key, preserving order; sets in place
     * if the property already exists.
     * @param {object} obj Object to mutate.
     * @param {string} anchor Existing key to insert after.
     * @param {string} key New key.
     * @param {*} value New value.
     */
    insertAfter(obj, anchor, key, value) {
        if (Object.prototype.hasOwnProperty.call(obj, key)) {
            obj[key] = value;
            return;
        }
        const entries = Object.entries(obj);
        for (const k of Object.keys(obj)) {
            delete obj[k];
        }
        for (const [k, v] of entries) {
            obj[k] = v;
            if (k === anchor) {
                obj[key] = value;
            }
        }
        if (!Object.prototype.hasOwnProperty.call(obj, key)) {
            obj[key] = value; // anchor absent: append
        }
    }

    /**
     * Rewrite tokens referencing swapped action steps across every string in
     * the document. Handles {{key}}, {{key.path}}, {{key[].path}} (with
     * Liquid filters) and {% for var in key %} loops; loop variables are
     * tracked so their fields validate against the array item schema.
     * @param {object} json Full template document (mutated).
     */
    rewriteTokens(json) {
        const walk = (node) => {
            if (Array.isArray(node)) {
                node.forEach((v, i) => { node[i] = walk(v); });
                return node;
            }
            if (node && typeof node === 'object') {
                for (const k of Object.keys(node)) {
                    node[k] = walk(node[k]);
                }
                return node;
            }
            if (typeof node === 'string') {
                return this.rewriteString(node);
            }
            return node;
        };
        walk(json.config);
    }

    /**
     * Rewrite all swapped-step token references inside one string value.
     * @param {string} str Original string.
     * @returns {string} Rewritten string.
     */
    rewriteString(str) {
        if (!str.includes('{')) {
            return str;
        }
        const loopVars = {}; // liquid loop var -> {entry, prefix}
        let out = str;

        for (const [key, entry] of Object.entries(this.swapped)) {
            const k = key.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

            // {% for var in key[.path] %}
            out = out.replace(
                new RegExp(`\\{%\\s*for\\s+(\\w+)\\s+in\\s+${k}((?:\\.[\\w.\\[\\]]+)?)\\s*%\\}`, 'g'),
                (m, loopVar, sub) => {
                    let p = sub.replace(/^\./, '');
                    if (entry.response_nest && !p) {
                        p = entry.response_nest;
                        this.report.tokens.push(`loop: ${key} -> ${key}.${p}`);
                    }
                    loopVars[loopVar] = { entry, prefix: p ? `${p}[]` : '[]' };
                    return `{% for ${loopVar} in ${key}${p ? `.${p}` : ''} %}`;
                },
            );

            // {{key...}} with optional [].path / .path and Liquid filters
            out = out.replace(
                new RegExp(`\\{\\{\\s*${k}((?:\\[\\])?(?:\\.[^}|]*)?)\\s*(\\|[^}]*)?\\}\\}`, 'g'),
                (m, rawPath, filters) => {
                    const rewritten = this.rewritePath(entry, key, rawPath || '');
                    return `{{${key}${rewritten}${filters ? ` ${filters.trim()}` : ''}}}`;
                },
            );
        }

        // Loop variable members: {{var.field}} validated against item schema.
        for (const [loopVar, ctx] of Object.entries(loopVars)) {
            const v = loopVar.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
            out = out.replace(
                new RegExp(`\\{\\{\\s*${v}\\.([^}|\\s]+)\\s*(\\|[^}]*)?\\}\\}`, 'g'),
                (m, fieldPath, filters) => {
                    const rewritten = this.resolveFieldPath(ctx.entry, `${loopVar}(loop)`, `${ctx.prefix}.${fieldPath}`, fieldPath);
                    return `{{${loopVar}.${rewritten}${filters ? ` ${filters.trim()}` : ''}}}`;
                },
            );
        }
        return out;
    }

    /**
     * Rewrite one token path suffix ("", "[].compare_at_price", ".gateway").
     * @param {object} entry Ops entry of the referenced step.
     * @param {string} key Step key (reporting only).
     * @param {string} rawPath Suffix as captured, with leading [] or dot.
     * @returns {string} Rewritten suffix.
     */
    rewritePath(entry, key, rawPath) {
        const arr = rawPath.startsWith('[]');
        let p = rawPath.replace(/^\[\]/, '').replace(/^\./, '').trim();

        if (!p) {
            // Bare {{key}} or {{key[]}}: only nesting applies.
            if (entry.response_nest) {
                this.report.tokens.push(`${key}: bare -> .${entry.response_nest}${arr ? '[]' : ''}`);
                return `.${entry.response_nest}${arr ? '[]' : ''}`;
            }
            return rawPath;
        }

        const schemaPath = `${entry.response_nest ? `${entry.response_nest}[].` : ''}${arr ? '[].' : ''}${p}`;
        const resolved = this.resolveFieldPath(entry, key, schemaPath, p);
        const prefix = entry.response_nest ? `.${entry.response_nest}[].` : (arr ? '[].' : '.');
        const result = `${prefix}${resolved}`;
        if (result !== rawPath) {
            this.report.tokens.push(`${key}: ${rawPath} -> ${result}`);
        }
        return result;
    }

    /**
     * Resolve a referenced response field path: exact match, curated rename,
     * then automatic snake->camel per segment. Loose schemas downgrade
     * misses to warnings; explicit schemas make them errors.
     * @param {object} entry Ops entry.
     * @param {string} key Step key (reporting only).
     * @param {string} schemaPath Path to validate against response_paths
     *   (includes [] markers and nest prefix).
     * @param {string} tokenPath The path portion that appears in the token.
     * @returns {string} The (possibly rewritten) token path portion.
     */
    resolveFieldPath(entry, key, schemaPath, tokenPath) {
        const paths = entry.response_paths;
        const prefixLen = schemaPath.length - tokenPath.length;

        const exists = (sp) => paths.includes(sp);
        const looseAt = (sp) => {
            const parts = sp.split('.');
            for (let i = parts.length - 1; i > 0; i--) {
                if (paths.includes(`${parts.slice(0, i).join('.')}.*`)) {
                    return true;
                }
            }
            return paths.includes('*');
        };

        if (exists(schemaPath)) {
            return tokenPath;
        }
        // Curated rename: longest matching prefix of the token path.
        const renames = Object.entries(entry.response_renames || {}).sort((a, b) => b[0].length - a[0].length);
        for (const [from, to] of renames) {
            if (tokenPath === from || tokenPath.startsWith(`${from}.`)) {
                const candidate = to + tokenPath.slice(from.length);
                if (exists(schemaPath.slice(0, prefixLen) + candidate) || looseAt(schemaPath.slice(0, prefixLen) + candidate)) {
                    return candidate;
                }
            }
        }
        // Automatic snake -> camel, per segment.
        const camel = tokenPath.split('.').map((seg) => camelize(seg)).join('.');
        if (camel !== tokenPath && exists(schemaPath.slice(0, prefixLen) + camel)) {
            this.report.tokens.push(`${key}: auto-camel ${tokenPath} -> ${camel}`);
            return camel;
        }
        if (looseAt(schemaPath)) {
            this.report.warnings.push(`${key}: token path "${tokenPath}" not verifiable (loose v2 schema), kept as-is`);
            return tokenPath;
        }
        this.report.errors.push(`${key}: token references "${tokenPath}" which is not in the v2 ${entry.v2.operation_id} response (blocker or add a rename)`);
        return tokenPath;
    }

    /** Print the migration report. */
    print() {
        const { swaps, tokens, warnings, errors } = this.report;
        console.log(`\n=== ${this.dir} ===`);
        swaps.forEach((s) => console.log(`  SWAP   ${s}`));
        tokens.forEach((t) => console.log(`  TOKEN  ${t}`));
        warnings.forEach((w) => console.log(`  WARN   ${w}`));
        errors.forEach((e) => console.log(`  ERROR  ${e}`));
        if (!swaps.length && !errors.length) {
            console.log('  (no shopify steps found)');
        }
    }
}

/**
 * CLI entry point.
 */
function main() {
    const args = process.argv.slice(2).filter((a) => a !== '--check');
    const check = process.argv.includes('--check');
    if (!args.length) {
        console.error('Usage: node bin/migrations/06-shopify-v2.js <template-dir> [--check]');
        process.exit(1);
    }
    const ops = JSON.parse(fs.readFileSync(OPS_FILE, 'utf8'));
    const ok = new Migrator(path.resolve(args[0]), ops).run(!check);
    process.exit(ok ? 0 : 2);
}

// Harness compatibility (bin/index.js migration runner): migrate the file's
// directory in write mode.
export default (res) => {
    const ops = JSON.parse(fs.readFileSync(OPS_FILE, 'utf8'));
    new Migrator(path.dirname(res), ops).run(true);
};

if (process.argv[1] && fileURLToPath(import.meta.url) === path.resolve(process.argv[1])) {
    main();
}
